protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();
    next loadModule();
    datatype.parmDatatypeId(extendedTypeNum(ETG_Estimation));
    datatype.parmReferenceHelp("@ETG_New:ETG_Estimation");
    datatype.parmWizardIsContinuous(false);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardIsChangeDownAllowed(NoYes::Yes);
    datatype.parmWizardIsChangeUpAllowed(NoYes::Yes);
    datatype.parmWizardHighest(999);
    datatype.parmSortField(20);
    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);

    this.create(datatype);

    datatype.parmDatatypeId(extendedTypeNum(ETGLineestimationno));
    datatype.parmReferenceHelp("@ETG_New:ETGLineestimationno");
    datatype.parmWizardIsContinuous(false);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardIsChangeDownAllowed(NoYes::Yes);
    datatype.parmWizardIsChangeUpAllowed(NoYes::Yes);
    datatype.parmWizardHighest(999);
    datatype.parmSortField(21);
    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);

    this.create(datatype);
}
